oxy_webhelp_navlinks = {"tocId-d30753e55223":{"topics":[{"title":"Multitenancy with <span class=\"ph\">RSC<\/span>","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">Rubrik Security Cloud<\/span> multitenancy uses a multi-account management framework that         enables a single primary <span class=\"ph\">Rubrik Security Cloud<\/span> account to provision, manage, and monitor         multiple <span class=\"ph\">Rubrik Security Cloud<\/span> environments. The architecture is designed to support both         shared infrastructure and strict physical isolation.<\/p>","href":"saas\/mt_multitenancy.html","attributes":{"data-id":"mt_multitenancy"},"menu":{"hasChildren":false},"tocID":"mt_multitenancy-d30753e55229","topics":[]},{"title":"Tenant Comparison","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">Rubrik Security Cloud<\/span> offers two multitenancy models to support different         requirements for resource isolation, administrative autonomy, and access to advanced         security applications.<\/p>","href":"saas\/mt_tenant_comparison.html","attributes":{"data-id":"mt_tenant_comparison"},"menu":{"hasChildren":false},"tocID":"mt_tenant_comparison-d30753e55250","topics":[]},{"title":"Organizations","shortdesc":"<p class=\"shortdesc\">Multitenancy in <span class=\"ph\">Rubrik Security Cloud<\/span> provides logical isolation of shared         compute, storage, and network resources in such a way that each organization can only access         its own data, especially for shared infrastructure platforms.<\/p>","href":"saas\/mt_organizations.html","attributes":{"data-id":"mt_organizations"},"menu":{"hasChildren":true},"tocID":"mt_organizations-d30753e55263","next":"mt_organizations-d30753e55263"},{"title":"Envoy and Organization Networks","shortdesc":"<p class=\"shortdesc\">With Rubrik Envoy, you can enable secure data movement between Rubrik clusters and a         tenant organization network.<\/p>","href":"cdm_old\/mt_envoy_org_networks.html","attributes":{"data-id":"mt_envoy_org_networks"},"menu":{"hasChildren":true},"tocID":"mt_envoy_org_networks-d30753e55580","next":"mt_envoy_org_networks-d30753e55580"},{"title":"Dedicated tenants","shortdesc":"<p class=\"shortdesc\">Dedicated <span class=\"ph\">Rubrik Security Cloud<\/span> tenants provide Managed Service Providers with         physically isolated <span class=\"ph\">Rubrik Security Cloud<\/span> instances for their clients, ensuring complete         data separation and feature parity across security applications.<\/p>","href":"saas\/mt_ded_tenant.html","attributes":{"data-id":"mt_ded_tenant"},"menu":{"hasChildren":true},"tocID":"mt_ded_tenant-d30753e55821","next":"mt_ded_tenant-d30753e55821"}]}};